import base64
import io
from typing import Optional

from PIL import Image

TEAM_LOGOS_B64 = {
    "Riptide": "",
    "Wardens": "",
    "Slimes": "",
    "Devilbats": "",
    "Vexes": "",
    "Raiders": "",
}

KNOWN_TEAMS_NO_LOGO = ["Parrots", "Traders", "Bees", "Sniffers", "Masons", "Shepherds"]

_cache = {}


def get_team_logo(team_name: str, size: int) -> Optional[Image.Image]:
    if not team_name:
        return None
    match = None
    for name in TEAM_LOGOS_B64:
        if name.lower() == team_name.strip().lower():
            match = name
            break
    if match is None:
        return None

    cache_key = (match, size)
    if cache_key in _cache:
        return _cache[cache_key]

    raw = base64.b64decode(TEAM_LOGOS_B64[match])
    img = Image.open(io.BytesIO(raw)).convert("RGBA")
    img = img.resize((size, size), Image.LANCZOS)
    _cache[cache_key] = img
    return img
